msg.payload.timestamp = new Date().toISOString();
// TODO: change station_id per physical device
msg.payload.station_id = "CALEUS_001";
msg.payload.station_location = "placeholder_lat,placeholder_lon";
return msg;

var d = msg.payload;
function mk(v,t){return {payload:v, topic:t};}
function windLabel(deg){
    var dirs=['N','NNE','NE','ENE','E','ESE','SE','SSE',
              'S','SSW','SW','WSW','W','WNW','NW','NNW'];
    return dirs[Math.round(deg/22.5)%16];
}
return [
    mk(d.temp_celsius,          'temp_celsius'),
    mk(d.wind_ms,               'wind_ms'),
    mk(d.uv_index,              'uv_index'),
    mk(d.noise_level_db,        'noise_level_db'),
    mk(d.humidity_percent,      'humidity_percent'),
    mk(d.air_pressure_hpa,      'air_pressure_hpa'),
    mk(d.wind_direction_degree+'° '+windLabel(d.wind_direction_degree),'wind_dir'),
    mk({x:new Date().toISOString(), y:d.temp_celsius},'Temperature °C'),
    mk({x:new Date().toISOString(), y:d.noise_level_db},'Noise dB')
];

var d = msg.payload;
function mk(v){return {payload:{value:v, data:d}};}
return [mk(d.uv_index), mk(d.wind_ms),
        mk(d.noise_level_db), mk(d.vibration_ms2)];

var v=msg.payload.value, d=msg.payload.data;
var lvl = v>=8?'very_high':v>=6?'high':'moderate';
msg.topic = 'alerts/park/'+d.station_id+'/uv';
msg.payload = {
    alert_type:'uv', level:lvl, value:v,
    station_id:d.station_id,
    location:d.station_location,
    timestamp:d.timestamp,
    message:'UV Index '+lvl.toUpperCase()+': '+v
};
return msg;

var v=msg.payload.value, d=msg.payload.data;
var lvl = v>=17?'storm':'strong';
msg.topic = 'alerts/park/'+d.station_id+'/wind';
msg.payload = {
    alert_type:'wind', level:lvl, value_ms:v,
    station_id:d.station_id,
    location:d.station_location,
    timestamp:d.timestamp,
    message:'Wind '+lvl.toUpperCase()+': '+v+' m/s'
};
return msg;

var v=msg.payload.value, d=msg.payload.data;
var lvl = v>=85?'spike_alert':'sustained_violation';
msg.topic = 'alerts/police/noise/'+d.station_id;
msg.payload = {
    alert_type:'noise', level:lvl, value_db:v,
    station_id:d.station_id,
    location:d.station_location,
    timestamp:d.timestamp,
    duration_exceeded_s:0,
    message:'Noise '+lvl+': '+v+'dB — Police Report'
};
return msg;

var v=msg.payload.value, d=msg.payload.data;
var lvl = v>=3?'high':'notable';
msg.topic = 'alerts/park/'+d.station_id+'/vibration';
msg.payload = {
    alert_type:'vibration', level:lvl, value_ms2:v,
    station_id:d.station_id,
    location:d.station_location,
    timestamp:d.timestamp,
    message:'Vibration '+lvl.toUpperCase()+': '+v+' m/s²'
};
return msg;

var v=msg.payload.value, d=msg.payload.data;
var atype = v>=8 ? 'earthquake_vibration'
          : v>=24 ? 'severe_storm'
          : 'extreme_uv';
msg.topic = 'alerts/global/severe/'+d.station_id;
msg.payload = {
    alert_type:atype, level:'critical', value:v,
    station_id:d.station_id,
    location:d.station_location,
    timestamp:d.timestamp,
    full_reading:d,
    message:'🚨 SEVERE: '+atype.toUpperCase()+' | '+v
};
return msg;

var log = flow.get('alert_log') || [];
var p = msg.payload;
var entry = new Date().toLocaleTimeString() + ' — ' + 
            p.alert_type.toUpperCase() + ' | ' + p.level + ' | ' + p.message;
log.unshift(entry);
if (log.length > 10) log.pop();
flow.set('alert_log', log);
msg.payload = log.join('<br>');
return msg;

